#include "hts221.h"
#include <Wire.h>
#include <Adafruit_HTS221.h>
static Adafruit_HTS221 hts;
static float _t=0,_h=0;static unsigned long _l=0;
void hts221_setup(){Wire.begin();if(!hts.begin_I2C()){Serial.println("[hts221] Fail!");return;}hts.setDataRate(HTS221_RATE_1_HZ);Serial.println("[hts221] OK");}
void hts221_loop(){if(millis()-_l<2000)return;_l=millis();sensors_event_t h,t;hts.getEvent(&h,&t);_t=t.temperature;_h=h.relative_humidity;}
float hts221_get_temperature(){return _t;}
float hts221_get_humidity(){return _h;}
